update.foreach:

-- Create computed column if it does not exist
IF NOT EXISTS (
    SELECT * FROM sys.computed_columns
    WHERE name = '${idx.computedColumnName}'
      AND object_id = OBJECT_ID('${tableName}')
)
BEGIN
    ALTER TABLE ${tableName}
    ADD ${idx.computedColumnName} 
        AS (${idx.expression}) PERSISTED;
END;

-- Create index if it does not exist
IF NOT EXISTS (
    SELECT * FROM sys.indexes
    WHERE name = '${idx.indexName}'
      AND object_id = OBJECT_ID('${tableName}')
)
BEGIN
    CREATE INDEX ${idx.indexName}
        ON ${tableName}(${idx.computedColumnName});
END


-- Drop index if it exists
IF EXISTS (
    SELECT * FROM sys.indexes
    WHERE name = '${idx.indexName}'
      AND object_id = OBJECT_ID('${tableName}')
)
BEGIN
    DROP INDEX ${idx.indexName} ON ${tableName};
END;

-- Drop computed column if it exists
IF EXISTS (
    SELECT * FROM sys.computed_columns
    WHERE name = '${idx.computedColumnName}'
      AND object_id = OBJECT_ID('${tableName}')
)
BEGIN
    ALTER TABLE ${tableName}
    DROP COLUMN ${idx.computedColumnName};
END;

